const crypto = require('crypto');
const secret = $env.REVIEW_HMAC_SECRET || 'fallback-secret';
const baseUrl = 'https://n8n.rodinah.dev/webhook/tax-review';
const metabaseUrl = 'http://hal-srvr:3002/dashboard/6';

// Filter out empty rows that postgres returns when there are no results
const records = $input.all().filter(r => r.json && r.json.doc_id != null);
const count = records.length;

function makeToken(docId, action) {
  return crypto.createHmac('sha256', secret)
    .update(`${docId}|${action}`)
    .digest('hex');
}

function makeLink(docId, action) {
  const token = makeToken(docId, action);
  return `${baseUrl}?action=${action}&doc_id=${docId}&token=${token}`;
}

function formatAmount(amount) {
  if (amount === null || amount === undefined) return '—';
  return '$' + parseFloat(amount).toFixed(2);
}

function formatDate(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-AU');
}

const header = `
<!DOCTYPE html>
<html>
<head><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:20px;background:#f9fafb">
  <div style="max-width:1000px;margin:0 auto;background:#fff;border-radius:8px;box-shadow:0 1px 4px rgba(0,0,0,.1);overflow:hidden">`;

const footer = `
    <div style="padding:16px 24px;border-top:1px solid #e2e8f0;text-align:center">
      <a href="${metabaseUrl}" style="color:#1e40af;font-size:13px;text-decoration:none">&#128202; Open Review Queue in Metabase</a>
    </div>
  </div>
</body>
</html>`;

let html, subject;

if (count === 0) {
  subject = 'TC Review — All Clear ✓';
  html = header + `
    <div style="background:#166534;padding:20px 24px">
      <h1 style="color:#fff;margin:0;font-size:20px">&#10003; Tax Collector — All Clear</h1>
      <p style="color:#bbf7d0;margin:6px 0 0;font-size:14px">No documents require review at this time</p>
    </div>
    <div style="padding:40px 24px;text-align:center">
      <p style="color:#555;font-size:15px;margin:0">All documents have been reviewed. Nothing to action.</p>
    </div>` + footer;
} else {
  subject = `TC Review Required — ${count} document${count !== 1 ? 's' : ''} awaiting decision`;
  const rows = records.map(r => {
    const d = r.json;
    const confirmUrl = makeLink(d.doc_id, 'confirm');
    const rejectUrl  = makeLink(d.doc_id, 'reject');
    return `
    <tr style="border-bottom:1px solid #eee">
      <td style="padding:10px 8px;font-size:13px;color:#666">${d.doc_id}</td>
      <td style="padding:10px 8px;font-size:13px;font-weight:600">${d.supplier_name}</td>
      <td style="padding:10px 8px;font-size:12px;color:#444;max-width:220px">${d.subject || '—'}</td>
      <td style="padding:10px 8px;font-size:12px">${d.category}</td>
      <td style="padding:10px 8px;font-size:13px;text-align:center">${d.confidence}</td>
      <td style="padding:10px 8px;font-size:13px;text-align:right">${formatAmount(d.total_amount)}</td>
      <td style="padding:10px 8px;font-size:12px;color:#666">${formatDate(d.document_date)}</td>
      <td style="padding:10px 8px;font-size:12px;color:#666">${d.fy_label || '—'}</td>
      <td style="padding:10px 8px;white-space:nowrap">
        <a href="${confirmUrl}" style="background:#22c55e;color:#fff;padding:6px 12px;border-radius:4px;text-decoration:none;font-size:13px;font-weight:600;margin-right:6px">&#10003; Confirm</a>
        <a href="${rejectUrl}"  style="background:#ef4444;color:#fff;padding:6px 12px;border-radius:4px;text-decoration:none;font-size:13px;font-weight:600">&#10007; Reject</a>
      </td>
    </tr>`;
  }).join('');

  html = header + `
    <div style="background:#1e40af;padding:20px 24px">
      <h1 style="color:#fff;margin:0;font-size:20px">&#128203; Tax Collector — Review Required</h1>
      <p style="color:#bfdbfe;margin:6px 0 0;font-size:14px">${count} document${count !== 1 ? 's' : ''} awaiting your decision</p>
    </div>
    <div style="padding:20px 24px">
      <table style="width:100%;border-collapse:collapse">
        <thead>
          <tr style="background:#f1f5f9">
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">ID</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">Supplier</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">Subject</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">Category</th>
            <th style="padding:10px 8px;text-align:center;font-size:12px;color:#64748b;font-weight:600">Conf.</th>
            <th style="padding:10px 8px;text-align:right;font-size:12px;color:#64748b;font-weight:600">Amount</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">Date</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">FY</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#64748b;font-weight:600">Action</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>` + footer;
}

return [{ json: { html, subject, count } }];
